from flask import Flask, request, jsonify
import cv2
import numpy as np
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from sklearn.metrics.pairwise import cosine_similarity

app = Flask(__name__)

# Sample data: list of tuples (image_path, label)
data = [
    ('path_to_employee1_photo.jpg', 'Employee1'),
    # Add more employee photos and labels as needed
]

def load_images_and_labels(data):
    images = []
    labels = []
    for img_path, label in data:
        image = cv2.imread(img_path, 0)  # Read as grayscale
        images.append(image)
        labels.append(label)
    return np.array(images), labels

images, labels = load_images_and_labels(data)

# Encode labels
label_encoder = LabelEncoder()
encoded_labels = label_encoder.fit_transform(labels)

def extract_features(image):
    # Simple example: convert image to a fixed-size feature vector (e.g., flattened array)
    return image.flatten()

# Extract features for all images
features = np.array([extract_features(img) for img in images])

# Train the model
model = SVC(kernel='linear', probability=True)
model.fit(features, encoded_labels)

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    img_file = request.files['image']
    img = cv2.imread(img_file.stream, 0)  # Read as grayscale
    feature_vector = extract_features(img).reshape(1, -1)
    
    probabilities = model.predict_proba(feature_vector)[0]
    
    # Get confidence scores for all training classes
    class_probabilities = dict(zip(label_encoder.classes_, probabilities))
    
    return jsonify(class_probabilities)

if __name__ == '__main__':
    app.run(debug=True)